  name = substr($0, 4)  # strip "jjs" prefix
  idx = index(name, "_")
  if (idx > 0) {
    prefix = substr(name, 1, idx - 1)
    word = substr(name, idx + 1)
  } else {
    prefix = name
    word = ""
  }
  print prefix "\t" word "\t" $0
}' | sort

